import { useState } from 'react'

interface ChipListProps {
  initial: string[]
}

export const ChipList = ({ initial }: ChipListProps) => {
  const [tags, setTags] = useState(initial)

  const remove = (t: string) => setTags((prev) => prev.filter((x) => x !== t))

  return (
    <ul role="group" aria-label="Selected filters">
      {tags.map((t) => (
        <li key={t}>
          <span>{t}</span>
          <button
            type="button"
            aria-label={`Remove ${t}`}
            onClick={() => remove(t)}
          >
            ×
          </button>
        </li>
      ))}
    </ul>
  )
}
